      "content": "const { randomUUID } = require('node:crypto');

let projectsStore = [];

async function createProject(name) {
  const project = {
    id: randomUUID(),
    name,
    members: [],
    tasks: []
  };
  projectsStore.push(project);
  return project;
}

async function getProjects() {
  return projectsStore;
}

module.exports = {
  createProject,
  getProjects
};
